public class WarehouseInfo
{
    public string WarehouseId { get; set; } = "WH-A";
    public string WarehouseName { get; set; } = "Warehouse A";

    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
        ("WH-D", "Warehouse D"),
    ];
}

namespace sv_9aecbf567da746cbbbe0c0d74cdadff2.Services;

/// <summary>
/// Scoped service (per circuit) that polls for low-stock alerts and
/// notifies all subscribed components when new data arrives.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private CancellationTokenSource? _cts;
    private string _warehouseId = string.Empty;

    public int LatestAlertCount { get; private set; }

    /// <summary>
    /// Fired on the calling thread whenever new alert data arrives.
    /// Subscribers must wrap StateHasChanged in InvokeAsync because
    /// the event fires from a background timer thread.
    /// </summary>
    public event Action? OnChange;

    /// <summary>Simulates a database query — returns a random count 0–15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Begins polling every 10 seconds for the given warehouse.
    /// Stops any existing poll first so only one runs at a time.
    /// </summary>
    public void StartPolling(string warehouseId)
    {
        StopPolling();
        _warehouseId = warehouseId;
        _cts = new CancellationTokenSource();
        _ = PollLoopAsync(_cts.Token);
    }

    public void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        // Fetch immediately on start, then every 10 s.
        await FetchAndNotifyAsync();

        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await FetchAndNotifyAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on StopPolling / Dispose.
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        LatestAlertCount = await GetLowStockCountAsync(_warehouseId);
        OnChange?.Invoke();
    }

    public void Dispose() => StopPolling();
}

