@* Interactive warehouse selector — placed in static MainLayout but rendered
   with its own InteractiveServer mode so it can handle change events. *@
@rendermode InteractiveServer
@using sv_9aecbf567da746cbbbe0c0d74cdadff2.Services
@inject CascadingValueSource<WarehouseInfo> WarehouseSource

<select class="form-select form-select-sm" style="width:auto;display:inline-block"
        value="@_selectedId" @onchange="OnWarehouseChanged">
    @foreach (var (id, name) in WarehouseInfo.AvailableWarehouses)
    {
        <option value="@id">@name</option>
    }
</select>

@code {
    private string _selectedId = "WH-A";

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? "WH-A";
        var name = WarehouseInfo.AvailableWarehouses
            .First(w => w.Id == _selectedId).Name;

        await WarehouseSource.NotifyChangedAsync(
            new WarehouseInfo { WarehouseId = _selectedId, WarehouseName = name });
    }
}

@* Low-stock alert badge — subscribes to InventoryAlertService.OnChange
   so it updates whenever ANY component triggers a poll refresh. *@
@rendermode InteractiveServer
@using sv_9aecbf567da746cbbbe0c0d74cdadff2.Services
@inject InventoryAlertService Alerts
@implements IDisposable

@if (Alerts.LatestAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill">@Alerts.LatestAlertCount</span>
}
else
{
    <span class="badge bg-success rounded-pill">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync because OnChange fires from a background timer thread.
        _handler = () => InvokeAsync(StateHasChanged);
        Alerts.OnChange += _handler;
    }

    public void Dispose()
    {
        Alerts.OnChange -= _handler;
    }
}

