@page "/dashboard"
@rendermode InteractiveServer
@using sv_9aecbf567da746cbbbe0c0d74cdadff2.Services
@inject InventoryAlertService Alerts
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard — @Warehouse?.WarehouseName</h1>

<div class="card mt-4" style="max-width:26rem">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text fs-2">
            @if (Alerts.LatestAlertCount > 0)
            {
                <span class="text-danger fw-bold">@Alerts.LatestAlertCount items below minimum</span>
            }
            else
            {
                <span class="text-success">All stock levels OK</span>
            }
        </p>
        <p class="text-muted small">Refreshes every 10 seconds</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private Action? _handler;
    private string _lastWarehouseId = string.Empty;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        Alerts.OnChange += _handler;
        StartPollingForCurrentWarehouse();
    }

    protected override void OnParametersSet()
    {
        // Restart polling when the cascading warehouse value changes.
        var currentId = Warehouse?.WarehouseId ?? "WH-A";
        if (currentId != _lastWarehouseId)
        {
            StartPollingForCurrentWarehouse();
        }
    }

    private void StartPollingForCurrentWarehouse()
